import{_ as e,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"11. Anti Discrimination","description":"","frontmatter":{"title":"11. Anti Discrimination","eba":"Health Allied & Managers Admin 2021-2025","topics":["disputes","preliminary","discrimination"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/preliminary/11-anti-discrimination.md","filePath":"ebas/has-managers-admin/common-terms/preliminary/11-anti-discrimination.md"}'),r={name:"ebas/has-managers-admin/common-terms/preliminary/11-anti-discrimination.md"};function o(s,i,c,m,l,p){return t(),n("div",null,[...i[0]||(i[0]=[a('<h1 id="_11-anti-discrimination" tabindex="-1">11. Anti Discrimination <a class="header-anchor" href="#_11-anti-discrimination" aria-label="Permalink to &quot;11. Anti Discrimination&quot;">​</a></h1><p><strong>11.1</strong> It is the intention of the parties covered by this Agreement to achieve the principal object in section 3(e) of the Act through respecting and valuing the diversity of the workforce by helping to prevent and eliminate discrimination on the basis of race, colour, sex, sexual preference, age, physical or mental disability, marital status, family responsibilities, pregnancy, religion, political opinion, national extraction or social origin.</p><p><strong>11.2</strong> Accordingly, in fulfilling their obligations under the procedures in <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">clause 17</a> (Dispute Resolution Procedure), the parties covered by this Agreement must make every endeavour to ensure that neither the provisions nor their operation are unlawfully discriminatory in their effects.</p><p><strong>11.3</strong> Nothing in this clause is to be taken to affect:</p><p><strong>(a)</strong> any different treatment (or treatment having different effects) which is specifically exempted under applicable anti-discrimination legislation;</p><p><strong>(b)</strong> an Employee, Employer or registered organisation pursuing matters of discrimination in any State or Federal jurisdiction, including by application to the Australian Human Rights Commission; or</p><p><strong>(c)</strong> any exemptions provided under the Act.</p><p>Plain language terms: discrimination, equal opportunity.</p>',8)])])}const u=e(r,[["render",o]]);export{h as __pageData,u as default};
